const body = $input.first().json.body || $input.first().json;
const from = body.From || '';
const mensaje = body.Body || '';
const phone = from.replace('whatsapp:', '');
return [{ json: { phone, mensaje, timestamp: new Date().toISOString() } }];

const products = $node['Consultar stock real de Shopify'].json.products || [];
const shop = $node['Obtener políticas de la tienda'].json.shop || {};

const productList = products.map(p => {
  const variants = p.variants || [];
  const variantInfo = variants.map(v => {
    const available = v.inventory_quantity > 0 ? `✅ ${v.inventory_quantity} uds` : '❌ Agotado';
    const varName = [v.option1, v.option2, v.option3].filter(Boolean).join(' / ');
    return `    - ${varName || 'Único'}: ${v.price}€ | ${available}`;
  }).join('\n');

  const desc = (p.body_html || '').replace(/<[^>]+>/g, '').substring(0, 200);
  return `PRODUCTO: ${p.title}\n${variantInfo}\n  Descripción: ${desc}`;
}).join('\n\n');

const context = `TIENDA: ${shop.name || ''}\nDOMINIO: https://${shop.domain || ''}\n\nPOLÍTICA ENVÍOS: Envío gratis desde 50€. Entrega en 24-48h laborables en España peninsular.\nPOLÍTICA DEVOLUCIONES: 30 días desde la recepción. Producto en estado original.\n\nCATÁLOGO ACTUALIZADO:\n${productList}`;

return [{ json: { context } }];

